from dataclasses import dataclass, field
from typing import Dict, List, Optional
import time
import numpy as np

@dataclass
class Metric:
    name: str
    value: float
    timestamp: float = field(default_factory=time.time)

@dataclass
class Alert:
    metric: str
    message: str
    severity: str
    timestamp: float = field(default_factory=time.time)

class ContinuousMonitor:
    """Continuously monitor and optimize performance."""

    def __init__(self, regression_threshold: float = 0.2):
        self.regression_threshold = regression_threshold
        self.baseline: Dict[str, float] = {}
        self.history: Dict[str, List[Metric]] = {}
        self.alerts: List[Alert] = []

    def set_baseline(self, metrics: Dict[str, float]):
        """Set baseline metrics."""
        self.baseline = metrics.copy()
        # Also record as first history point
        for name, value in metrics.items():
            self.history[name] = [Metric(name=name, value=value)]

    def record(self, metrics: Dict[str, float]):
        """Record new metrics."""
        timestamp = time.time()

        for name, value in metrics.items():
            # Initialize history if needed
            if name not in self.history:
                self.history[name] = []

            # Add to history
            self.history[name].append(Metric(name=name, value=value, timestamp=timestamp))

            # Check for regression
            alert = self.check_regression(name, value)
            if alert:
                self.alerts.append(alert)

    def check_regression(self, metric: str, value: float) -> Optional[Alert]:
        """Check if value indicates regression from baseline."""
        if metric not in self.baseline:
            return None

        baseline = self.baseline[metric]
        if baseline == 0:
            return None

        change_ratio = (value - baseline) / baseline

        # Regression = value increased beyond threshold (for metrics where lower is better)
        if change_ratio > self.regression_threshold:
            severity = 'critical' if change_ratio > 0.5 else 'warning'
            return Alert(
                metric=metric,
                message=f"{metric} regressed by {change_ratio*100:.1f}% from baseline",
                severity=severity
            )

        return None

    def analyze_trend(self, metric: str) -> Dict:
        """Analyze trend for a metric."""
        if metric not in self.history or len(self.history[metric]) < 3:
            return {'trend': 'insufficient_data', 'data_points': len(self.history.get(metric, []))}

        values = [m.value for m in self.history[metric]]
        x = np.arange(len(values))

        # Linear regression
        coeffs = np.polyfit(x, values, 1)
        slope = coeffs[0]

        # Determine trend based on slope relative to mean
        mean = np.mean(values)
        if mean == 0:
            trend = 'stable'
        elif slope > 0.05 * mean:
            trend = 'increasing'
        elif slope < -0.05 * mean:
            trend = 'decreasing'
        else:
            trend = 'stable'

        return {
            'trend': trend,
            'slope': slope,
            'current': values[-1],
            'baseline': values[0],
            'change_pct': ((values[-1] - values[0]) / values[0] * 100) if values[0] != 0 else 0,
            'data_points': len(values)
        }

    def get_recommendations(self) -> List[str]:
        """Get recommendations based on trends."""
        recommendations = []

        for metric in self.history:
            trend = self.analyze_trend(metric)

            if trend['trend'] == 'increasing' and trend.get('change_pct', 0) > 20:
                recommendations.append(
                    f"Investigate {metric}: increased {trend['change_pct']:.1f}% from baseline. "
                    f"Consider profiling recent changes."
                )
            elif trend['trend'] == 'increasing' and trend.get('change_pct', 0) > 10:
                recommendations.append(
                    f"Monitor {metric}: gradual increase detected ({trend['change_pct']:.1f}% from baseline)."
                )

        # Add recommendations based on alerts
        recent_alerts = [a for a in self.alerts if time.time() - a.timestamp < 3600]
        if recent_alerts:
            recommendations.append(
                f"Address {len(recent_alerts)} recent alerts - check regression causes."
            )

        return recommendations

    def print_status(self):
        """Print monitoring status."""
        print("\n" + "=" * 50)
        print("CONTINUOUS MONITORING STATUS")
        print("=" * 50)

        print("\nMetric Trends:")
        for metric in self.history:
            trend = self.analyze_trend(metric)
            icon = {'increasing': '📈', 'decreasing': '📉', 'stable': '➡️'}
            print(f"  {icon.get(trend['trend'], '❓')} {metric}: {trend['trend']}")
            if 'change_pct' in trend:
                print(f"     Change from baseline: {trend['change_pct']:+.1f}%")

        print(f"\nAlerts: {len(self.alerts)}")
        for alert in self.alerts[-5:]:
            print(f"  [{alert.severity}] {alert.message}")

        recs = self.get_recommendations()
        print(f"\nRecommendations:")
        for rec in recs:
            print(f"  • {rec}")


# Test
if __name__ == "__main__":
    monitor = ContinuousMonitor(regression_threshold=0.2)

    # Set baseline
    monitor.set_baseline({'runtime_ms': 100, 'memory_mb': 500})

    # Simulate metrics over time (runtime increasing, memory stable)
    for i in range(10):
        monitor.record({
            'runtime_ms': 100 + i * 5,  # Gradually increasing
            'memory_mb': 500 + np.random.normal(0, 10)  # Stable with noise
        })

    monitor.print_status()
